prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT (COUNT(*) AS ?namedCount) WHERE {
  ?model a bboExt:Model .
  {
    ?model tai:normalizedId "4ac969819d6749d495c4f3be5f4745de" .
  } UNION {
    ?model tai:originalId "4ac969819d6749d495c4f3be5f4745de" .
  }
  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .
  ?elem tai:belongsTo ?choreo .
  ?elem bbo:name ?n .
  FILTER(STRLEN(STR(?n)) > 0)
}

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?name WHERE {
  ?model a bboExt:Model .
  {
    ?model tai:normalizedId "4ac969819d6749d495c4f3be5f4745de" .
  } UNION {
    ?model tai:originalId "4ac969819d6749d495c4f3be5f4745de" .
  }
  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .
  ?elem tai:belongsTo ?choreo .
  ?elem bbo:name ?name .
  FILTER(STRLEN(STR(?name)) > 0)
}
ORDER BY LCASE(STR(?name))
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?sourceName ?targetName ?directReach ?reachable WHERE {
  ?model a bboExt:Model .
  {
    ?model tai:normalizedId "4ac969819d6749d495c4f3be5f4745de" .
  } UNION {
    ?model tai:originalId "4ac969819d6749d495c4f3be5f4745de" .
  }
  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .

  ?source tai:belongsTo ?choreo ; bbo:name ?sourceName .
  FILTER(CONTAINS(LCASE(STR(?sourceName)), LCASE("receive documents")))

  ?target tai:belongsTo ?choreo ; bbo:name ?targetName .
  FILTER(CONTAINS(LCASE(STR(?targetName)), LCASE("application received")))

  BIND(EXISTS {
    ?edge a bbo:SequenceFlow .
    ?edge bbo:has_sourceRef ?source .
    ?edge bbo:has_targetRef ?target .
  } AS ?directReach)

  BIND(EXISTS {
    ?source ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?target .
  } AS ?reachable)

}LIMIT 25
